const epicResponse = $input.first().json;
const epicKey = epicResponse.key;
const epicTitle = $('Parse Epic Markdown').first().json.epicTitle;
const taskMarkdowns = $('Parse Epic Markdown').first().json.taskMarkdowns || [];
const storyType = $env.JIRA_STORY_ISSUE_TYPE || 'Story';

if (taskMarkdowns.length === 0) {
  return [{ json: { epicKey, epicTitle, tasks: [], taskCount: 0, noTasks: true } }];
}

return taskMarkdowns.map((md, i) => {
  const parsed = parseMarkdown(md);
  const taskBody = buildJiraBody(parsed, storyType, epicKey);
  return { json: { taskBody, taskTitle: parsed.title, epicKey, epicTitle, taskIndex: i } };
});

const epicKey = $('Prepare Tasks').first().json.epicKey;
const epicTitle = $('Prepare Tasks').first().json.epicTitle;
const jiraBase = $env.JIRA_BASE_URL;

const taskItems = $input.all();
const tasks = taskItems.map(item => ({
  key: item.json.key,
  title: item.json.fields?.summary || '',
  url: jiraBase + '/browse/' + item.json.key
}));

return [{ json: {
  success: true,
  epic: { key: epicKey, title: epicTitle, url: jiraBase + '/browse/' + epicKey },
  tasks,
  taskCount: tasks.length
} }];

